// API V40.6 協議：批量收集 SKU (Supabase-Ready 版)
// File guard wrapped in outer try-catch — safe even if fs/path unavailable on NAS
let _fg = { status: 'skipped', path: '', cwd: '', err: '' };
try {
  const fs = require('fs');
  const path = require('path');
  const cwd = process.cwd();
  const home = process.env.HOME || process.env.USERPROFILE || '/root';
  const n8nUserFolder = process.env.N8N_USER_FOLDER || process.env.N8N_USER_DATA_FOLDER || '';
  _fg.cwd = cwd;
  _fg.home = home;
  _fg.n8nUserFolder = n8nUserFolder;

  const dirs = [
    ...(n8nUserFolder ? [require('path').join(n8nUserFolder, 'data')] : []),
    path.join(home, '.n8n', 'data'),
    path.join(cwd, '.n8n', 'data'),
    '/root/.n8n/data',
    '/home/node/.n8n/data',
    '/volume1/@appstore/n8n/var/.n8n/data',
    '/var/packages/n8n/var/.n8n/data',
  ];

  for (const dir of dirs) {
    try {
      const fp = path.join(dir, 'products.json');
      if (!fs.existsSync(fp)) {
        fs.mkdirSync(dir, { recursive: true });
        fs.writeFileSync(fp, '{}');
        _fg.status = 'created';
      } else {
        _fg.status = 'already_exists';
      }
      _fg.path = fp;
      break;
    } catch(e) {
      _fg.status = 'dir_failed:' + e.message;
      continue;
    }
  }
} catch(e) {
  // require('fs') blocked or other top-level error — do NOT throw, continue with SKU logic
  _fg.status = 'require_failed:' + e.message;
  _fg.err = e.message;
}

const items = $input.all();

if (!Array.isArray(items) || items.length === 0) {
    return { json: { batchFormula: "RECORD_ID()='INVALID'", sku_list: [], hasItems: false, _fg } };
}

const skus = [...new Set(items.map(i => i.json.Search_SKU).filter(s => s && s !== "無商品"))];

if (skus.length === 0) {
    return { json: { batchFormula: "RECORD_ID()='INVALID'", sku_list: [], hasItems: false, _fg } };
}

const formulaParts = skus.map(s => `{Product_Name} = '${s}'`);
const finalFormula = skus.length > 1 ? `OR(${formulaParts.join(',')})` : formulaParts[0];

return { json: { batchFormula: finalFormula, sku_list: skus, hasItems: true, _fg } };
